var canReorderDoubled = function(arr) {
    const count = new Map();
    arr.sort((a, b) => Math.abs(a) - Math.abs(b));

    for (const a of arr) {
        if (!count.has(a)) {
            count.set(a, 0);
        }
        count.set(a, count.get(a) + 1);
    }

    for (const a of count.keys()) {
        if (count.get(a) > 0) {
            const target = a < 0 ? a / 2 : a * 2;
            if (!count.has(target) || count.get(target) < count.get(a)) {
                return false;
            }
            count.set(target, count.get(target) - count.get(a));
        }
    }

    return true;
};
```

    1. Count values in the dataArray using a map / dictionary / counter.
2. For each value in the dataArray, in ascending order of magnitude (Take care of negative values properly):
     - Check if we have sufficient values to match the count.
     - If we do, remove the required count and continue. Else, return False.
3. If our loop encounters no issues, return True.

